def get_index_statistics(index_path: str) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index."""
    try:
        searcher = LeannSearcher(index_path)
    except Exception:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}")

    pm = searcher.passage_manager
    passages = pm.get_all_passages()

    metadata_fields = set()
    field_value_counts = defaultdict(Counter)

    for passage in passages:
        metadata = passage.metadata
        for field_name, value in metadata.items():
            metadata_fields.add(field_name)
            field_value_counts[field_name][value] += 1

    # Convert to regular dict for JSON serialization
    field_value_counts_dict = {}
    for field, counter in field_value_counts.items():
        field_value_counts_dict[field] = dict(counter)

    return {
        "total_passages": len(passages),
        "metadata_fields": sorted(list(metadata_fields)),
        "field_value_counts": field_value_counts_dict
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields."""
    try:
        searcher = LeannSearcher(index_path)
    except Exception:
        raise FileNotFoundError(f"Index metadata file not found at {index_path}")

    pm = searcher.passage_manager
    passages = pm.get_all_passages()

    total_passages = len(passages)
    passages_with_all_fields = 0
    field_presence = defaultdict(int)
    required_fields_set = set(required_fields)
    missing_fields = []

    for passage in passages:
        has_all_fields = True
        passage_fields = set(passage.metadata.keys())
        for field in required_fields:
            if field not in passage_fields:
                has_all_fields = False
                if field not in missing_fields:
                    missing_fields.append(field)
                break
        if has_all_fields:
            passages_with_all_fields += 1
        else:
            for field in required_fields:
                if field in passage_fields:
                    field_presence[field] += 1

    # Remove duplicates from missing_fields
    missing_fields = list(set(missing_fields))

    coverage_percentage = (passages_with_all_fields / total_passages) * 100 if total_passages > 0 else 0

    field_coverage = {}
    for field in required_fields:
        if total_passages > 0:
            field_coverage[field] = (field_presence[field] / total_passages) * 100
        else:
            field_coverage[field] = 0

    return {
        "coverage_percentage": round(coverage_percentage, 2),
        "field_coverage": field_coverage,
        "missing_fields": missing_fields
    }

